type TabConfig = {
  key: TabKey;
  label: string;
  activeIcon: React.ReactNode;
  inactiveIcon: React.ReactNode;
  onPress?: () => void;
};

const Bar = React.forwardRef<HTMLDivElement, BarProps>((
  {
    activeTab,
    variant = 'Home',
    tabs,
    showLabels = true,
    tabIcon,
    tabLabel,
    onTabChange,
    onHomePress,
    onMeetingsPress,
    onActionsPress,
    onNotificationsPress,
    onClick,
    onHover,
    isDisabled = false,
    isLoading = false,
    children,
    sx,
    className,
  },
  ref
) => {
  const currentTab: TabKey = activeTab ?? variant;

  const tabConfigs: TabConfig[] = [
    {
      key: 'Home',
      label: 'Home',
      activeIcon: <HomeIconActive />,
      inactiveIcon: <HomeIconInactive />,
      onPress: onHomePress,
    },
    {
      key: 'Meetings',
      label: 'Meetings',
      activeIcon: <MeetingsIconActive />,
      inactiveIcon: <MeetingsIconInactive />,
      onPress: onMeetingsPress,
    },
    {
      key: 'Actions',
      label: 'Actions',
      activeIcon: <ActionsIconActive />,
      inactiveIcon: <ActionsIconInactive />,
      onPress: onActionsPress,
    },
    {
      key: 'Notifications',
      label: 'Notifications',
      activeIcon: <NotificationsIconActive />,
      inactiveIcon: <NotificationsIconInactive />,
      onPress: onNotificationsPress,
    },
  ];

  const handleTabClick = (tab: TabConfig) => {
    if (isDisabled) return;
    tab.onPress?.();
    onTabChange?.(tab.key);
    onClick?.();
  };

  return (
    <MuiBox
      ref={ref}
      data-figma-component="Bar"
      className={className}
      sx={{background: 'var(--gradient-gradients-custom)', 
        position: 'relative',
        overflow: 'hidden',
        width: '375px',
        height: '74px',
        color: 'var(--color-white-white, #FFFFFF)',
        opacity: isDisabled ? 0.5 : 1,
        flexShrink: 0,
        ...sx,
      }}
      onMouseEnter={onHover}
    >
      {/* decorative overlays — exact from Figma manifest */}
      <div aria-hidden="true" style={{ position: 'absolute', pointerEvents: 'none', zIndex: 1, left: '-13px', top: '0px', width: '115px', height: '67px', background: 'rgba(153,89,255,0.35)', opacity: 0.7, borderRadius: '12px', filter: 'blur(42.6px)' }} />
      <div aria-hidden="true" style={{ position: 'absolute', pointerEvents: 'none', zIndex: 1, left: '163px', top: '2px', width: '113px', height: '71px', background: 'rgba(0,255,255,0.3)', opacity: 0.7, borderRadius: '12px', filter: 'blur(42.6px)' }} />
      <div aria-hidden="true" style={{ position: 'absolute', pointerEvents: 'none', zIndex: 1, left: '72px', top: '2px', width: '128px', height: '70px', background: 'rgba(48,116,243,0.4)', opacity: 0.7, borderRadius: '12px', filter: 'blur(42.6px)' }} />
      <div aria-hidden="true" style={{ position: 'absolute', pointerEvents: 'none', zIndex: 1, left: '67px', top: '4px', width: '117px', height: '71px', background: 'rgba(255,152,0,0.3)', opacity: 0.7, borderRadius: '12px', filter: 'blur(42.6px)' }} />

      {/* Background SVG overlay */}
      <MuiBox
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          pointerEvents: 'none',
          zIndex: 0,
          '& svg': { width: '100%', height: '100%', display: 'block' },
        }}
        dangerouslySetInnerHTML={{ __html: BG_SVG }}
      />

      {/* Tab items */}
      <MuiBox
        sx={{
          position: 'relative',
          zIndex: 1,
          display: 'flex',
          flexDirection: 'row',
          alignItems: 'center',
          justifyContent: 'center',
          gap: 'var(--gap-space-l, 20px)',
          width: '377px',
          height: '75px',
          minHeight: '75px',
        }}
      >
        {tabConfigs.map((tab) => {
          const isActive = currentTab === tab.key;
          return (
            <MuiBox
              key={tab.key}
              onClick={() => handleTabClick(tab)}
              sx={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                gap: 'var(--size-shadow-blur-6, 6px)',
                padding: '12px 0px',
                width: tab.key === 'Notifications' ? 'fit-content' : '72px',
                minWidth: tab.key === 'Notifications' ? '72px' : '72px',
                height: '75px',
                minHeight: '75px',
                cursor: isDisabled ? 'default' : 'pointer',
                userSelect: 'none',
              }}
            >
              <MuiBox
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  width: tab.key === 'Home' ? '20px' : tab.key === 'Meetings' ? '21px' : tab.key === 'Actions' ? '14px' : '17px',
                  height: tab.key === 'Home' ? '19px' : tab.key === 'Meetings' ? '21px' : tab.key === 'Actions' ? '20px' : '20px',
                  flexShrink: 0,
                }}
              >
                {isActive ? tab.activeIcon : tab.inactiveIcon}
              </MuiBox>
              {showLabels !== false && (
                <MuiTypography
                  sx={{
                    fontSize: '12px',
                    fontWeight: isActive ? 600 : 400,
                    fontFamily: 'Inter',
                    lineHeight: 'normal',
                    color: 'rgba(255, 255, 255, 1)',
                    whiteSpace: 'nowrap',
                  }}
                >
                  {tab.label}
                </MuiTypography>
              )}
            </MuiBox>
          );
        })}
      </MuiBox>

      {children}
    </MuiBox>
  );
});

Bar.displayName = 'Bar';

export { Bar };
